function nowMs(){return Date.now();}
function dub(){return new Date().toLocaleString('en-IE',{timeZone:'Europe/Dublin',hour12:false});}
function mins(){var d=new Date();return parseInt(d.toLocaleString('en-IE',{timeZone:'Europe/Dublin',hour:'2-digit',hour12:false}),10)*60+parseInt(d.toLocaleString('en-IE',{timeZone:'Europe/Dublin',minute:'2-digit'}),10);}
var st=flow.get('st')||{};
function residentHome(){return RESIDENTS.some(function(r){return st[r.person]==='home'||st[r.ping]==='on';});}
function guestHome(){return GUESTS.some(function(g){return st[g.person]==='home'||st[g.ping]==='on';});}
function anyoneHome(){return residentHome()||guestHome();}
function indoorAny(){return INDOOR.some(function(e){return st[e]==='on';});}
function indoorRecent(){return (nowMs()-(flow.get('lastIndoorMotion')||0))<OCC_LOOKBACK;}
function mode(){return flow.get('mode')||st['input_select.house_mode']||'Home';}
function holdActive(){return (flow.get('manual_until')||0)>nowMs();}
function clrAway(){var t=context.get('awayTimer');if(t){clearTimeout(t);context.set('awayTimer',null);}}
function scheduleAway(delay){context.set('awayTimer',setTimeout(attemptAway,delay));}
function attemptAway(){
  context.set('awayTimer',null);
  if(anyoneHome()||st['input_boolean.maintenance_mode']==='on'||holdActive()){return;}
  if(indoorAny()||indoorRecent()){node.warn('[house-mode] away deferred: indoor motion - retry 20m');scheduleAway(AWAY_MS);return;}
  if(mode()!=='Away') emitMode('Away','all residents left (20m)');
}
function nightWindow(){var m=mins(); return m>=NIGHT_LO || m<NIGHT_HI;}
function quietLevel(){return st['binary_sensor.lg_tv_online']!=='on' && st['binary_sensor.samsung_tv_online']!=='on' && !indoorAny() && st['light.sitting_room']!=='on';}
function emitMode(opt,reason){
  if(mode()===opt)return;
  flow.set('mode',opt); flow.set('last_auto',opt); st['input_select.house_mode']=opt; flow.set('st',st);
  node.send([{entity:'input_select.house_mode',option:opt},null,null,{payload:'House mode → '+opt+'  ('+reason+')'},{payload:dub()+'  MODE '+opt+'  ('+reason+')\n'},{payload:reason}]);
}
function emitOverlay(id,on,reason){
  var ent='input_boolean.'+id; if((st[ent]==='on')===on)return;
  st[ent]=on?'on':'off'; flow.set('st',st);
  node.send([null, on?{entity:ent}:null, on?null:{entity:ent}, {payload:(on?'Overlay ON: ':'Overlay OFF: ')+id+'  ('+reason+')'}, {payload:dub()+'  OVERLAY '+id+'='+(on?'on':'off')+'  ('+reason+')\n'}, null]);
}
function evaluate(){
  var warn=(st['sensor.met_eireann_warning_level']||'none').toString().toLowerCase();
  emitOverlay('storm_mode',(warn==='orange'||warn==='red'),'Met Éireann '+warn);
  if(st['input_boolean.maintenance_mode']==='on'){var ms=flow.get('maint_since'); if(ms&&nowMs()-ms>MAINT_MS) emitOverlay('maintenance_mode',false,'4h auto-expire');}
  if(st['input_boolean.maintenance_mode']==='on'){ clrAway(); if(mode()==='Away') emitMode('Home','maintenance active'); return; }
  if(holdActive()){clrAway();return;}
  var m=mode(); if(m==='Sleeping')return;
  if(!anyoneHome()){
    if(!context.get('awayTimer')) scheduleAway(AWAY_MS);
    return;
  }
  clrAway();
  if(m==='Away'){ emitMode('Home','resident returned'); return; }
  var la=flow.get('last_activity'); if(la===undefined){flow.set('last_activity',nowMs()); la=nowMs();}
  if(m==='Home' && residentHome() && nightWindow() && quietLevel() && (nowMs()-la>=SLEEP_MS) && nowMs()>(flow.get('sleep_block_until')||0)){
    emitMode('Sleeping','quiet 20m, no activity (22:00–07:00)');
  }
}
var T=msg.topic;
// seed from ha-get-entities (array)
if(Array.isArray(msg.payload)){
  var want={}; WATCH.forEach(function(w){want[w]=1;});
  msg.payload.forEach(function(e){ if(e&&e.entity_id&&want[e.entity_id]) st[e.entity_id]=e.state; });
  if(INDOOR.some(function(e){return st[e]==='on';})) flow.set('lastIndoorMotion',nowMs());
  flow.set('st',st);
  if(T==='presence'){
    var indoorFired=INDOOR.indexOf(msg.eid)>=0&&st[msg.eid]==='on';
    if(indoorFired){ flow.set('last_activity',nowMs()); flow.set('lastIndoorMotion',nowMs()); if(mode()==='Sleeping'&&mins()>=WAKE_FROM){flow.set('sleep_block_until',nowMs()+WAKE_BLOCK_MS);emitMode('Home','morning activity ('+(msg.eid||T)+')');} }
  } else if(T!=='tick'){ flow.set('mode', st['input_select.house_mode']||flow.get('mode')||'Home'); flow.set('last_activity',nowMs()); }
  evaluate(); return null;
}
if(msg.eid && !Array.isArray(msg.payload)){ st[msg.eid]=msg.payload; flow.set('st',st); }
// activity = any light change, any dimmer press, or an indoor sensor turning on
var act=(T==='lights')||(T==='tv')||(T==='dimmer');
if(act){
  flow.set('last_activity',nowMs());
  if(mode()==='Sleeping' && mins()>=WAKE_FROM){ flow.set('sleep_block_until',nowMs()+WAKE_BLOCK_MS); emitMode('Home','morning activity ('+(msg.eid||T)+')'); }
}
if(T==='tick'){ evaluate(); return null; }
if(T==='manual'){
  var uid=(msg.ent&&msg.ent.context&&msg.ent.context.user_id)||null;
  if(uid===NR) return null;
  if(msg.eid==='input_select.house_mode'){ flow.set('mode',msg.payload); flow.set('manual_until',nowMs()+HOLD_MS); node.send([null,null,null,null,{payload:dub()+'  MANUAL house_mode='+msg.payload+' (hold 4h)\n'},{payload:'changed by hand'}]); }
  else if(msg.eid==='input_boolean.maintenance_mode'){ flow.set('maint_since', msg.payload==='on'?nowMs():null); }
  return null;
}
evaluate();
return null;

flow.set('residents',[
  {person:'person.colm_finn',   ping:'binary_sensor.colm_phone_home'},
  {person:'person.olivia_finn', ping:'binary_sensor.olivia_phone_home'},
  // add when Cian has a phone: {person:'person.cian_finn', ping:'binary_sensor.cian_phone_home'},
]);
flow.set('guests',[
  {person:'person.daire_finn', ping:'binary_sensor.daire_phone_home'},
]);
return msg;

const r=msg.payload; if(!r) return null;
const a=r.after||{}; if(a.severity!=='alert') return null;
const cam=a.camera||'';
if((cam==='Rear_Door'||cam==='Rear_Shed') && flow.get('patio_open')) return null;
const objs=([...new Set(((a.data&&a.data.objects)||[]).map(o=>o.replace(/-verified$/,'')))]);
const det=(a.data&&a.data.detections)||[];
const label=objs.length?objs.join(', '):'Motion';
const cl=label.charAt(0).toUpperCase()+label.slice(1);
const names={Front_Car:'Front Car',Front_Van:'Front Van',Rear_Door:'Rear Door',Rear_Shed:'Rear Shed',Doorbell:'Doorbell'};
const camName=names[cam]||cam;
const subs=(a.data&&a.data.sub_labels)||[]; const personName=((objs.indexOf('person')!==-1)&&subs.length&&subs[0])?subs[0]:null;
const NB=env.get('NABU_URL');
const rid=a.id; const rkey='rev_'+String(rid).split('.').join('_');
const gif=NB+'/api/frigate/notifications/'+rid+'/review_preview.gif';
const snap=det.length?(NB+'/api/frigate/notifications/'+det[0]+'/snapshot.jpg?bbox=1'):null;
const clip=det.length?(NB+'/api/frigate/notifications/'+det[0]+'/'+cam+'/clip.mp4'):null;
const tm=new Date((a.start_time||Date.now()/1000)*1000).toLocaleTimeString('en-IE',{timeZone:'Europe/Dublin',hour:'2-digit',minute:'2-digit'});
const type=r.type;
const GMAP={Front_Car:'front',Front_Van:'front',Doorbell:'doorbell',Rear_Door:'rear',Rear_Shed:'rear'};
const GLABEL={front:'Front',doorbell:'Doorbell',rear:'Rear'};
const PRIO={Front_Car:1,Front_Van:2,Doorbell:1,Rear_Door:1,Rear_Shed:2};
const KLABEL={person:'Person',car:'Vehicle',motorcycle:'Motorcycle',bicycle:'Bicycle',package:'Package',umbrella:'Umbrella'};
function ohas(l){return objs.indexOf(l)!==-1;}
let kind=null;
if(ohas('person')) kind='person'; else if(ohas('car')||ohas('truck')) kind='car'; else if(ohas('motorcycle')) kind='motorcycle'; else if(ohas('bicycle')) kind='bicycle'; else if(ohas('package')) kind='package'; else if(ohas('umbrella')) kind='umbrella';
const kindLabel=kind?KLABEL[kind]:'';
const group=GMAP[cam]||null;
const WINDOW=120000;
if(kind && group){
  const gl=GLABEL[group]; const gkey='grp_'+group+'_'+kind;
  if(type==='new'||type==='update'){
    let grp=flow.get(gkey);
    const newInc=(!grp||(Date.now()-grp.lastAt)>WINDOW);
    if(newInc) grp={tag:'frig_'+group+'_'+kind+'_'+rid,cams:[],snap:null,snapCam:null,gif:null,gifCam:null,clip:null,lastAt:0,firstCam:cam};
    const had=grp.cams.indexOf(camName)!==-1;
    if(!had) grp.cams.push(camName);
    if(!grp.firstCam) grp.firstCam=cam;
    if(snap && cam===grp.firstCam){ grp.snap=snap; grp.snapCam=cam; if(clip) grp.clip=clip; }
    grp.lastAt=Date.now(); flow.set(gkey,grp); flow.set(rkey,{gkey:gkey,tag:grp.tag});
    let door=null;
    if(cam==='Doorbell'&&kind==='person'&&!had) door={camName:camName,gif:gif,snap:snap,tag:grp.tag,_src:'doorbell'};
    const titl='\ud83d\udcf7 '+(personName||kindLabel)+' \u2014 '+gl; const body=grp.cams.join(', ')+' at '+tm; const msgs=[];
    if(newInc){
      msgs.push({_src:'push-grp',title:titl,message:body,ndata:{tag:grp.tag,channel:'Cameras'}});
      if(grp.snap){ const nd={tag:grp.tag,channel:'Cameras',image:grp.snap}; if(grp.clip){nd.clickAction=grp.clip;nd.url=grp.clip;} msgs.push({_src:'push-grp-snap',title:titl,message:body,ndata:nd}); }
    } else if(!had){
      const nd={tag:grp.tag,channel:'Cameras'}; const img=grp.gif||grp.snap; if(img) nd.image=img; if(grp.clip){nd.clickAction=grp.clip;nd.url=grp.clip;}
      msgs.push({_src:'push-grp',title:titl,message:body,ndata:nd});
    }
    return [msgs.length?msgs:null, door];
  }
  if(type==='end'){
    const meta=flow.get(rkey); flow.set(rkey,undefined);
    if(!meta||!meta.gkey) return null;
    let grp=flow.get(meta.gkey);
    if(!grp||grp.tag!==meta.tag) return null;
    const prio=PRIO[cam]||99; const cur=grp.gifCam?(PRIO[grp.gifCam]||99):999;
    if(cam!==grp.firstCam || grp.gifCam) return null;
    grp.gif=gif; grp.gifCam=cam; if(clip) grp.clip=clip; flow.set(meta.gkey,grp);
    const parts=meta.gkey.split('_'); const gl2=GLABEL[parts[1]]; const kl2=KLABEL[parts[2]]||parts[2];
    const nd={tag:grp.tag,image:grp.gif,channel:'Cameras'}; if(grp.clip){nd.clickAction=grp.clip;nd.url=grp.clip;}
    return [{_src:'push-grp-gif:'+cam,title:'\ud83d\udcf7 '+(personName||kl2)+' \u2014 '+gl2,message:grp.cams.join(', '),ndata:nd},null];
  }
  return null;
}
if(type==='new'||type==='update'){
  if(flow.get(rkey)) return null;
  if(Date.now()-(flow.get('push_'+label)||0)<60000){ flow.set(rkey,'skip'); return null; }
  flow.set('push_'+label,Date.now()); flow.set(rkey,'sent');
  const titl=cl+' detected \u2014 '+camName; const body=cl+' detected - '+camName+' at '+tm;
  const msgs=[{_src:'push-instant',title:titl,message:body,ndata:{tag:'frigate_'+rid,channel:'Cameras'}}];
  if(snap){ const nd={tag:'frigate_'+rid,channel:'Cameras',image:snap}; if(clip){nd.clickAction=clip;nd.url=clip;} msgs.push({_src:'push-snap',title:titl,message:body,ndata:nd}); }
  return [msgs,null];
}
if(type==='end'){
  const st=flow.get(rkey); flow.set(rkey,undefined);
  if(st!=='sent') return null;
  const nd={tag:'frigate_'+rid,image:gif,channel:'Cameras'}; if(clip){nd.clickAction=clip;nd.url=clip;}
  return [{_src:'push-gif',title:cl+' \u2014 '+camName,message:cl+' at '+camName+' ('+tm+')',ndata:nd},null];
}
return null;

if (flow.get('house_mode') === 'Sleeping') return null;
const newv = Number(msg.payload);
if (!(newv > 0)) return null;
// entityId valueType is flaky on this palette version (came through empty on a
// real An Post detection 17-06-2026 -> blank " has landed"). Prefer eventData.
const eid = (msg.data && (msg.data.entity_id || (msg.data.new_state && msg.data.new_state.entity_id))) || msg.topic || '';
const key = eid.replace('sensor.front_car_','').replace('sensor.front_van_','').replace('_count','');
const names = {dpd:'DPD', gls:'GLS', amazon:'Amazon', ups:'UPS', fedex:'FedEx', dhl:'DHL', an_post:'On Fwuisht'};
const name = names[key];
if (!name) { node.warn('courier: unresolved entity_id "' + eid + '" topic "' + (msg.topic || '') + '" - no announcement'); return null; }
const now = Date.now();
if (now - (flow.get('cour_' + key) || 0) < 300000) return null;
flow.set('cour_' + key, now);
if (now - (flow.get('delivery_tts') || 0) < 120000) return null;
flow.set('delivery_tts', now);
msg._src = 'courier'; msg.message = name + ' has landed.';
return msg;

if (flow.get('house_mode') === 'Sleeping') return null;
const now = Date.now();
if (now - (flow.get('postman') || 0) < 300000) return null;
flow.set('postman', now);
if (now - (flow.get('delivery_tts') || 0) < 120000) return null;
flow.set('delivery_tts', now);
msg._src = 'postman'; msg.message = 'The postman has been detected. You have post or a package.';
return msg;

const ts = new Date().toLocaleString('en-IE',{timeZone:'Europe/Dublin',hour12:false});
let src = msg._src || 'event';
let what = msg.title || msg.message || ('doorbell ' + (msg.camName||''));
msg.payload = ts + '  [' + src + ']  ' + what + '\n';
return msg;

const ents=Array.isArray(msg.entities)?msg.entities:[];
const S=id=>{const e=ents.find(x=>x.entity_id===id);return e&&e.state;};
const f=S('sensor.doorbell_last_recognized_face');
const bad=['none','unknown','clear','unavailable',''];
const name=(f&&bad.indexOf(String(f).toLowerCase())===-1)?f:null;
const who=name||'Person';
const snap=msg.snap||null;
const tag=msg.tag;
node.warn('[cam] doorbell person: '+who+(snap?'':' (no snap)'));
const shield={who:who,image:snap};
const cast=snap?{url:snap}:null;
const phone=name?{title:'👤 '+name+' at the doorbell',message:'Doorbell',ndata:{tag:tag,channel:'Cameras',image:snap}}:null;
return [shield,cast,phone];

const r=msg.payload; if(!r) return null;
const a=r.after||{};
if(a.severity!=='alert') return null;
if(r.type!=='new' && r.type!=='update') return null;
const cam=a.camera||'';
if(cam!=='Front_Car' && cam!=='Front_Van') return null;
const objs=[...new Set(((a.data&&a.data.objects)||[]).map(o=>o.replace(/-verified$/,'')))]; 
if(objs.indexOf('person')===-1) return null;
const zones=((a.data&&a.data.zones)||[]).map(z=>String(z).toLowerCase());
if(zones.indexOf('182_focus_zone')===-1 && zones.indexOf('162_focus_zone')===-1) return null;
// fire when house is Sleeping (replaces fixed 23:00-06:30 window)
if(flow.get('house_mode') !== 'Sleeping') return null;
// cooldown 120s (strobe runs ~30s)
const last=flow.get('car_last')||0;
if(Date.now()-last < 120000) return null;
flow.set('car_last', Date.now());
const now=new Date();
const ts=now.toLocaleString('en-IE',{timeZone:'Europe/Dublin',hour12:false});
const line={payload:ts+'  [car-deterrent] person in focus zone - '+cam+'\n'};
node.send([{}, {}, line]);
return null;

const ev = msg.payload || {};
const mode = ev.new_state ? ev.new_state.state : '';
if (mode) flow.set('house_mode', mode);
node.warn('[cam-concierge] house_mode: ' + mode);
return null;

const ents = Array.isArray(msg.payload) ? msg.payload : [];
const hm = ents.find(x => x.entity_id === 'input_select.house_mode');
const mode = hm ? hm.state : 'Home';
// This seed re-runs every 120s to self-heal a missed state change, so warning on
// every pass wrote ~720 lines a day of pure noise -- which buries the warnings that
// actually mean something. Say it only when the value CHANGES (incl. the first seed).
const prev = flow.get('house_mode');
flow.set('house_mode', mode);
if (mode !== prev) node.warn('[cam-concierge] house_mode seeded: ' + mode);
return null;

if(flow.get('house_mode')==='Away'){
  msg.ndata=msg.ndata||{};
  msg.ndata.ttl=0;
  msg.ndata.priority='high';
  msg.ndata.channel='Cameras Away';
  msg.ndata.importance='high';
  if(msg.title&&msg.title.indexOf('\u26a0')!==0)msg.title='\u26a0\ufe0f '+msg.title;
}
return msg;

// === Heating controller — House Mode + time + 2h BOOST + forecast pre-heat (02-07-2026; dash boost 04-07-2026) ===
// Netatmo holds flat eco 19 baseline; this flow only RAISES via HomeKit set_temperature.
// Out1 -> set thermostat; Out2 -> test notify (change only, quiet 22:00-07:00); Out3 -> input_text.heating_status + heating_status_by (the badge WHO, ha-config #38).
const TEMP = { eco: 19, comfort: 20, night: 19.5, hot: 20.5, frost: 12 };
const BOOST_MS = 2 * 60 * 60 * 1000;   // manual override holds 2 hours
const MORNING_HOUR = 7;                // morning comfort warm-up starts 07:00 (base; forecast can bring earlier)
const PROX_M = 10000;                  // proximity pre-heat: within 10 km AND heading towards home -> comfort
// WHO pressed the dashboard boost/cancel button: the watcher nodes attach the button
// entity (with its service-call context) as msg.byEvent -- heat-get only replaces
// msg.payload, so it survives. Unknown/absent user -> 'hand' (same as the dial).
const BY_USERS = {
  'da11950c94184bf281a21b4b1a06cdb7': 'Colm',
  'bfe92889b07b4798901d5d48a789262f': 'Olivia',
  '5aa07e1f90c44da2aab995628305cb52': 'Cian',
  '848fa8f992bb47d6a23f498d73717814': 'Daire'
};
const pressBy = (() => {
  const uid = msg.byEvent && msg.byEvent.context && msg.byEvent.context.user_id;
  return (uid && BY_USERS[uid]) || 'hand';
})();

const ents = Array.isArray(msg.payload) ? msg.payload : [];
const get = id => ents.find(e => e.entity_id === id);
const ds = d => d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0') + '-' + String(d.getDate()).padStart(2, '0');

// Guest mode: ONLY block Away (never let the house go cold with guests in);
// Sleeping and Home run as normal (overnight 19.5, 7am warm-up, forecast pre-heat all still apply).
const guestOn = (() => { const g = get('input_boolean.guest_mode'); return g ? g.state === 'on' : false; })();
const hmRaw = (get('input_select.house_mode') || {}).state || 'Home';
const hm = (guestOn && hmRaw === 'Away') ? 'Home' : hmRaw;
const hmDisplay = guestOn ? hm + ' (guest)' : hm;
const mode = String(hm).toLowerCase();

// Extended-away 24h deep setback (helper defaults ON if absent)
const extToggle = get('input_boolean.heating_extended_away');
const extendedAwayEnabled = extToggle ? (extToggle.state === 'on') : true;
const EMPTY_LIMIT_MS = 24 * 60 * 60 * 1000;
let emptySince = context.get('emptySince');
if (mode === 'away') { if (!emptySince) emptySince = Date.now(); } else emptySince = null;
context.set('emptySince', emptySince);
const longAway = !!emptySince && (Date.now() - emptySince) >= EMPTY_LIMIT_MS;

const now = new Date();
const nowMs = Date.now();
const mins = now.getHours() * 60 + now.getMinutes();
const hour = now.getHours();
const between = (m, sH, sM, eH, eM) => m >= sH * 60 + sM && m < eH * 60 + eM;
const hhmm = ms => { const d = new Date(ms); return String(d.getHours()).padStart(2, '0') + ':' + String(d.getMinutes()).padStart(2, '0'); };

// --- scheduled target ---
let schedMode;
if (mode !== 'away') flow.set('preheat_latch', false);   // any exit from Away clears the pre-heat latch
if (mode === 'away') {
  // Proximity pre-heat: within 10 km AND heading towards home -> warm for arrival.
  // LATCHED: GPS direction flaps towards/stationary between fixes (glitch seen 05-07-2026:
  // setpoint bounced 20 -> 18.5 -> 20 mid-approach). Once on, pre-heat holds for the rest of
  // Away unless the person clearly leaves again (beyond PROX_CLEAR_M or distance unknown).
  const PROX_CLEAR_M = 12000;
  const pDist = parseFloat((get('sensor.12_the_oaks_nearest_distance') || {}).state);
  const pDir = (get('sensor.12_the_oaks_nearest_direction_of_travel') || {}).state;
  let preheat = flow.get('preheat_latch') || false;
  if (!isNaN(pDist) && pDist <= PROX_M && pDir === 'towards') preheat = true;
  if (isNaN(pDist) || pDist > PROX_CLEAR_M) preheat = false;
  flow.set('preheat_latch', preheat);
  schedMode = preheat ? 'comfort' : ((longAway && extendedAwayEnabled) ? 'frost' : 'eco');
} else if (mode === 'sleeping') {
  let sm = (hour >= MORNING_HOUR && hour < 12) ? 'comfort' : 'night';
  // Forecast pre-heat: bring the morning comfort forward on cold mornings (set nightly by the fc sub-flow)
  const ph = flow.get('preHeat');
  if (ph && ph.day === ds(now) && nowMs >= ph.startMs && hour < MORNING_HOUR) sm = 'comfort';
  schedMode = sm;
} else {
  schedMode = between(mins, 19, 0, 22, 0) ? 'hot' : 'comfort';
}
const schedTarget = TEMP[schedMode];

// --- manual boost detection (confirmed-setpoint method; immune to poll lag) ---
// A confirmed external setpoint change ABOVE the scheduled target = 2h boost.
// A change AT or BELOW the scheduled target (dial turned down / Netatmo app boost deleted ->
// device reverts to its 19 baseline) = CANCEL any boost; the schedule reasserts. Never a "boost down".
const climate = get('climate.netatmo_smart_thermostat');
const curSet = climate && climate.attributes ? climate.attributes.temperature : null;
const lastTarget = context.get('lastTarget');
let confirmed = context.get('confirmed') || false;
let boostUntil = context.get('boostUntil') || 0;
let boostTemp = context.get('boostTemp');
let boostNote = null; // overrides the notify text for boost cancel/decline

if (curSet != null && lastTarget != null && curSet === lastTarget) confirmed = true;
if (mode !== 'away' && confirmed && curSet != null && lastTarget != null && curSet !== lastTarget
    && !(boostUntil > nowMs && curSet === boostTemp)) {
  if (curSet > schedTarget) {
    boostTemp = curSet;
    boostUntil = nowMs + BOOST_MS;       // start / restart the 2h hold (dial path; gated to occupied modes)
    context.set('boostBy', 'hand');      // dial: no user context exists -> person unknown
  } else if (boostUntil > nowMs) {
    boostUntil = 0; boostTemp = null;    // turned down to/below schedule -> cancel boost
    context.set('cancelBy', 'hand');
    boostNote = 'Boost cancelled - back to schedule';
  }
  context.set('boostTemp', boostTemp);
  context.set('boostUntil', boostUntil);
}
context.set('confirmed', confirmed);

// --- dashboard boost commands (input_buttons via msg.topic) ---
if (msg.topic === 'boost-start') {
  const bt = parseFloat((get('input_number.heating_boost_temperature') || {}).state);
  if (!isNaN(bt)) {
    boostTemp = bt;
    boostUntil = nowMs + BOOST_MS;
    context.set('boostTemp', boostTemp);
    context.set('boostUntil', boostUntil);
    context.set('boostBy', pressBy);
    if (mode === 'away') context.set('awayBoost', true);   // deliberate pre-warm before returning (#30)
  }
}
if (msg.topic === 'boost-cancel' && boostUntil > nowMs) {
  boostUntil = 0; boostTemp = null;
  context.set('boostTemp', null);
  context.set('boostUntil', 0);
  context.set('cancelBy', pressBy);
  boostNote = 'Boost cancelled - back to schedule';
}

// Cancel any active boost the moment the house goes Away (don't heat an empty house) --
// unless the boost was STARTED while Away: a deliberate pre-warm before returning (#30).
if (mode === 'away' && boostUntil > nowMs && !context.get('awayBoost')) { boostUntil = 0; boostTemp = null; }
if (mode !== 'away' || !(boostUntil > nowMs)) context.set('awayBoost', false);

const boosting = boostUntil > nowMs;
if (!boosting) { context.set('boostUntil', 0); context.set('boostTemp', null); }

const effectiveMode = boosting ? 'boost' : schedMode;
const target = boosting ? boostTemp : schedTarget;

// --- WHY is the number what it is? (pure state, names the DRIVER of the current
// target -- never a transition. 16-07-2026 rewrite.) Occupancy presets (eco/frost/
// heading-home/sleep) are HOUSE-MODE driven; comfort & hot are SCHEDULE (clock) driven --
// the preset tells you which, so a mode move that leaves the number alone can no longer
// re-narrate the ticker (fixed '7:23 wake re-narrated an unchanged 20 deg' + 'evening arrival
// called someone-came-home'). hmReasonRaw is still read: a hand-changed mode marks (manual).
const hmReasonRaw = ((get('input_text.house_mode_reason') || {}).state || '').trim();

const phNow = (function () {           // forecast pre-heat running right now?
  const ph = flow.get('preHeat');
  return !!(ph && ph.day === ds(now) && nowMs >= ph.startMs && hour < MORNING_HOUR && mode === 'sleeping');
})();

const reason = (function () {
  if (boosting) return 'you asked';
  if (mode === 'away' && flow.get('preheat_latch')) return 'heading home';   // heading back
  if (phNow) return 'cold morning';                                          // forecast pre-heat
  if (schedMode === 'night') return 'sleep';                                 // asleep (night setback)
  if (schedMode === 'frost') return 'empty over 24h';                        // empty >24h
  if (schedMode === 'eco') return 'nobody home';                             // away, nobody in
  // comfort / hot while home or awake -- the number is the SCHEDULE's, named by the clock:
  if (hour >= 22 || hour < 7) return 'night';
  if (hour >= 19) return 'evening';                                          // 19:00-21:59 hot 20.5
  if (hour >= 10) return 'daytime';
  return 'morning';                                                          // 07:00-09:59
})();

// --- status text (out3; only written when it changes) ---
const _preset = effectiveMode + ' ' + target + '°';   // the PRESET and the temperature
const _base = boosting ? ('boost ' + target + '°') : _preset;
const _reason = boosting ? ('until ' + hhmm(boostUntil)) : (guestOn ? 'guest' : reason);
// WHO changed it: a boost (the hallway dial or the app button) and a hand-changed house
// mode are the only things a PERSON does. Everything else is Node-RED, on its schedule
// or on presence -> 'auto'.
const _by = (boosting || /changed by hand/i.test(hmReasonRaw)) ? 'manual' : 'auto';
const statusText = ((_reason ? (_base + ' — ' + _reason) : _base) + ' (' + _by + ')').slice(0, 100);   // input_text max=100; an over-long line is REJECTED by HA and the ticker silently dies
// A real change = the preset/temperature, its DRIVER (the reason word), guest, or who did
// it -- NOT the house mode itself: a mode move that leaves the number and its driver alone
// (waking to a 20 deg the morning schedule already set) must not rewrite the line. The
// pure-state reason can't flap on the heartbeat, so keying on it is safe.
const statusKey = _base + '|' + _reason + '|' + (guestOn ? 'g' : '-') + '|' + _by;
// WHO for the activity badge (ha-config #38): a boost line carries its starter (a person,
// or 'hand' for the dial); the schedule line written by a cancel carries the canceller;
// everything else is the engine on schedule/presence = 'Node-RED'.
const _statusBy = boosting ? (context.get('boostBy') || 'hand')
                           : (context.get('cancelBy') || 'Node-RED');
if (!boosting) context.set('boostBy', null);
let statusMsg = null;
if (statusKey !== context.get('lastStatusKey')) {
  context.set('lastStatusKey', statusKey);
  context.set('lastStatus', statusText);
  statusMsg = { statusText: statusText, statusBy: _statusBy };
}
context.set('cancelBy', null);   // one-shot: only the write in the cancel's own run may claim it

// --- de-dupe + 30-min re-assert ---
const lastTs = context.get('lastTs') || 0;
const stale = (nowMs - lastTs) > 30 * 60 * 1000;
if (lastTarget === target && !stale) {
  // no thermostat write needed; still surface status changes + boost notes (quiet hours apply)
  let n2 = null;
  if (boostNote && !(hour >= 22 || hour < 7)) n2 = { notify_title: 'Heating', notify_message: boostNote };
  return [null, n2, statusMsg];
}
const changed = (lastTarget !== target);
context.set('lastTarget', target);
context.set('lastTs', nowMs);
context.set('confirmed', false);          // wait for the entity to reflect this new write

msg.target = target;
msg.info = { houseMode: hmDisplay, effectiveMode, target, boosting, longAway };

const boostMins = boosting ? Math.round((boostUntil - nowMs) / 60000) : 0;
node.status({
  fill: boosting ? 'yellow' : (mode === 'away' ? 'blue' : (mode === 'sleeping' ? 'grey' : 'green')),
  shape: 'dot',
  text: boosting ? ('BOOST ' + target + 'C ' + boostMins + 'm left') : (hmDisplay + ' -> ' + effectiveMode + ' ' + target + 'C')
});

// --- test notification: change only, quiet 22:00-07:00 ---
let notifyMsg = null;
const nightQuiet = (hour >= 22 || hour < 7);
if (changed && !nightQuiet) {
  let m;
  if (boostNote) {
    m = boostNote + ' (' + effectiveMode + ' ' + target + 'C)';
  } else if (boosting) {
    m = 'Boost ' + target + 'C, holding until ' + hhmm(boostUntil);
  } else {
    m = hmDisplay + ' -> ' + effectiveMode + ' ' + target + 'C';
  }
  notifyMsg = { notify_title: 'Heating', notify_message: m };
}
return [msg, notifyMsg, statusMsg];

// === Nightly forecast pre-heat decision (~21:30) ===
// Reads the Met Éireann hourly forecast (from heat-fc-get) and decides how early to
// start tomorrow's 07:00 warm-up. Sets flow.preHeat for heat-fn. NO notification (removed 02-07-2026).
const MORNING_HOUR = 7;
const p = msg.payload || {};
let fc = p.forecast
  || (p['weather.forecast_home'] && p['weather.forecast_home'].forecast)
  || (msg.response && msg.response.forecast)
  || [];
if (!Array.isArray(fc)) fc = [];
if (fc.length === 0) {
  node.warn('preheat: forecast empty. msg keys=' + JSON.stringify(Object.keys(msg)) + ' payload keys=' + JSON.stringify(typeof p === 'object' ? Object.keys(p) : typeof p));
}

const now = new Date();
const ds = d => d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0') + '-' + String(d.getDate()).padStart(2, '0');

// tomorrow-morning entries: future, local (Dublin) hour 5..7
const morning = fc
  .map(x => ({ d: new Date(x.datetime), t: x.temperature }))
  .filter(x => x.d > now && x.d.getHours() >= 5 && x.d.getHours() <= 7 && x.t != null);

if (!morning.length) {
  node.warn('preheat: no morning forecast entries (payload shape?)');
  node.status({ fill: 'grey', shape: 'ring', text: 'no forecast' });
  return null;
}

const minTemp = Math.min(...morning.map(x => x.t));
let lead = 0;
if (minTemp < -3) lead = 60;
else if (minTemp < 0) lead = 45;
else if (minTemp < 4) lead = 30;
else if (minTemp < 8) lead = 15;
node.warn('preheat check: fc=' + fc.length + ' morning=' + morning.length + ' minTemp=' + minTemp + ' lead=' + lead);

if (lead === 0) {
  flow.set('preHeat', null);
  node.status({ fill: 'green', shape: 'dot', text: 'no preheat (' + minTemp + 'C)' });
  return null;                       // mild enough -> no early start
}

const day = morning[0].d;
const start = new Date(day.getFullYear(), day.getMonth(), day.getDate(), MORNING_HOUR, 0, 0);
start.setMinutes(start.getMinutes() - lead);
const hhmm = String(start.getHours()).padStart(2, '0') + ':' + String(start.getMinutes()).padStart(2, '0');

flow.set('preHeat', { day: ds(day), startMs: start.getTime(), leadMins: lead, temp: minTemp });
node.status({ fill: 'yellow', shape: 'dot', text: 'preheat ' + hhmm + ' (' + minTemp + 'C)' });

// Notify ONLY when the forecast low is sub-zero / freezing (user 02-07-2026)
if (minTemp < 0) {
  msg.notify_title = '❄️ Freezing morning ahead';
  msg.notify_message = 'Low around ' + minTemp + '°C overnight — I\'ll start warming the house early, from ' + hhmm + '.';
  return msg;
}
return null;                         // above-freezing pre-heat happens silently (no push)

// SINGLE source of truth. Add Cian here (create their ping sensor too).
const PEOPLE=[
 {name:'Colm',   person:'person.colm_finn',   ping:'binary_sensor.colm_phone_home',   notify:'notify.mobile_app_np3'},
 {name:'Olivia', person:'person.olivia_finn', ping:'binary_sensor.olivia_phone_home', notify:'notify.mobile_app_pixel_6a'},
 {name:'Daire',  person:'person.daire_finn',  ping:'binary_sensor.daire_phone_home',  notify:'notify.mobile_app_pixel_9a', onlyWhenHome:true}
 // ,{name:'Cian',  person:'person.cian_finn',  ping:'binary_sensor.cian_phone_home',  notify:'notify.mobile_app_pixel_7a'}
];
flow.set('people',PEOPLE);
global.set('people',PEOPLE);   // shared with the Alarm NFC Tags flow
return null;

// Alarm notification engine (state-derived) -> all people
const PEOPLE=flow.get('people')||[{notify:'notify.mobile_app_np3'},{notify:'notify.mobile_app_pixel_6a'}];
const ents=Array.isArray(msg.entities)?msg.entities:[];
const S=id=>{const e=ents.find(x=>x.entity_id===id);return e&&e.state;};
const homeP=p=>S(p.person)==='home'||S(p.ping)==='on';
const FN=id=>{const e=ents.find(x=>x.entity_id===id);return (e&&e.attributes&&e.attributes.friendly_name)||id.split('.').pop().replace(/_contact$/,'').replace(/_/g,' ').replace(/\b\w/g,c=>c.toUpperCase());};
const PERSONS=['cian','colm','aoife','olivia','daire'];
const spoken=id=>{const nm=FN(id).trim();const w=nm.split(/\s+/);return (PERSONS.includes(w[0].toLowerCase())&&w.length>1)?(w[0]+"'s "+w.slice(1).join(' ').toLowerCase()):('the '+nm.toLowerCase());};
const ev=msg.payload||{};
const ns=ev.new_state||{}, os=ev.old_state||{};
const nw=ns.state, old=os.state, eid=ev.entity_id||'';
const area=eid.endsWith('.shed')?'Shed':'House';
if(eid==='alarm_control_panel.house'&&nw){flow.set('alarm_house',nw);global.set('alarm_house',nw);}
if(eid==='alarm_control_panel.shed'&&nw){global.set('alarm_shed',nw);}
const ARMED=['armed_away','armed_home','armed_night','armed_vacation','armed_custom_bypass'];
const opens=(ns.attributes&&ns.attributes.open_sensors)||null;
function ol(){ if(!opens) return ''; try{return ' Open: '+Object.keys(opens).map(id=>FN(id)).join(', ')+'.';}catch(e){return '';} }
let title=null,message=null,tag=null;
if(ARMED.includes(nw)&&!ARMED.includes(old)){title='🔒 '+area+' alarm armed';message='The '+area+' alarm is now armed.';tag='armed';}
else if(nw==='triggered'){title='🚨 '+area+' alarm TRIGGERED';message='The '+area+' alarm has been triggered!'+ol();tag='trig';}
else if(old==='triggered'&&nw!=='triggered'){title='✅ '+area+' alarm clear';message='The '+area+' alarm is no longer triggered.';tag='untrig';}
else if(nw==='disarmed'&&(ARMED.includes(old)||old==='triggered'||old==='pending'||old==='arming')){title='🔓 '+area+' alarm disarmed';message='The '+area+' alarm has been disarmed.';tag='disarm';}
else if(nw==='disarmed'&&opens&&(old==='disarmed'||old==='arming')){title='⚠️ '+area+' failed to arm';message='The '+area+' alarm failed to arm.'+ol();tag='failed';}
else { return null; }
const key=tag+'|'+message, last=context.get('last_'+eid);
if(last===key) return null;
context.set('last_'+eid,key);
node.warn('[alarm-notify] '+area+' '+tag+' -> '+PEOPLE.filter(p=>p.notify&&(!p.onlyWhenHome||homeP(p))).length+' people');
const ICON={armed:'mdi:shield-lock',trig:'mdi:alarm-light',untrig:'mdi:shield-check',disarm:'mdi:shield-off',failed:'mdi:shield-alert'};
const ico=ICON[tag]||'mdi:shield-home';
const out=PEOPLE.filter(p=>p.notify&&(!p.onlyWhenHome||homeP(p))).map(p=>({payload:{action:p.notify,data:{title:title,message:message,data:{notification_icon:ico}}}}));
const _aw=flow.get('awaitWelcome');const _welcomePending=!!(_aw&&(Date.now()-_aw.since)<8*60*1000);
let sm=null;
if(tag==='armed') sm=(nw==='armed_night')?null:(area+' alarm armed.');
else if(tag==='disarm') sm=(old==='armed_night')?null:((eid==='alarm_control_panel.house'&&_welcomePending)?null:(area+' alarm disarmed.'));
else if(tag==='trig') sm='Warning! The '+area+' alarm has been triggered.';
else if(tag==='untrig') sm='The '+area+' alarm is no longer triggered.';
else if(tag==='failed'){const ks=opens?Object.keys(opens):[];const isHouse=(eid==='alarm_control_panel.house');if(isHouse&&flow.get('failSpoken')){sm=null;}else{if(isHouse)flow.set('failSpoken',true);sm=ks.length===1?('Alarm failed to arm because '+spoken(ks[0])+' is open.'):'Alarm failed to arm. Multiple windows and or doors are open. Check Home Assistant.';}}
return [out, sm?{payload:{message:sm}}:null];

// Layer 3: low-battery alerts (alarm presence) -> Colm+Olivia
// Day (07-22): immediate low (<15%) + immediate recovery (>=15% AND charging).
// Night (22-07): silent, record events for the 07:00 catch-up summary.
const d=msg.data||{};
const eid=d.entity_id||msg.topic;
const nv=parseFloat(msg.payload);
const ov=parseFloat(d.old_state&&d.old_state.state);
if(isNaN(nv)) return null;
const ents=msg.entities||[];
const S=id=>{const e=ents.find(x=>x.entity_id===id);return e?e.state:undefined;};
const NAME={'sensor.np3_battery_level':"Colm's",'sensor.pixel_6a_battery_level':"Olivia's"};
const STATE={'sensor.np3_battery_level':'sensor.np3_battery_state','sensor.pixel_6a_battery_level':'sensor.pixel_6a_battery_state'};
const who=NAME[eid];
if(!who) return null;
const charging=S(STATE[eid])==='charging';
const h=new Date().getHours();
const night=(h>=22||h<7);
const hhmm=()=>{const t=new Date();return ('0'+t.getHours()).slice(-2)+':'+('0'+t.getMinutes()).slice(-2);};
const ALERTS=['notify.mobile_app_np3','notify.mobile_app_pixel_6a'];
const push=(title,message)=>[ALERTS.map(a=>({payload:{action:a,data:{title:title,message:message,data:{notification_icon:'mdi:battery-alert'}}}}))];
// down-crossing below 15%
if(nv<15 && !(ov<15)){
  if(night){
    const rec=flow.get('battNight')||{};
    rec[eid]={who:who,lowPct:nv,lowAt:hhmm(),recovered:false};
    flow.set('battNight',rec);
    node.warn('[low-batt] night low '+eid+' '+nv+'% recorded');
    return null;
  }
  node.warn('[low-batt] '+eid+' '+nv+'%');
  return push('Phone battery low',who+' phone is at '+nv+'% - charge it so the alarm presence keeps working.');
}
// up-crossing above 15% AND charging -> recovery
if(nv>=15 && ov<15 && charging){
  if(night){
    const rec=flow.get('battNight')||{};
    const e=rec[eid]||{who:who,recovered:false};
    e.recovered=true; e.recPct=nv; e.recAt=hhmm();
    rec[eid]=e; flow.set('battNight',rec);
    node.warn('[low-batt] night recovery '+eid+' '+nv+'% recorded');
    return null;
  }
  node.warn('[low-batt] recovery '+eid+' '+nv+'%');
  return push('Phone battery recovering',who+' phone is back above 15% ('+nv+'%) and charging - alarm presence is covered again.');
}
return null;

// 07:00 overnight battery catch-up summary -> Colm+Olivia (only if events occurred)
const rec=flow.get('battNight')||{};
const eids=Object.keys(rec);
if(eids.length===0) return null;
const ents=msg.entities||[];
const S=id=>{const e=ents.find(x=>x.entity_id===id);return e?e.state:undefined;};
const STATE={'sensor.np3_battery_level':'sensor.np3_battery_state','sensor.pixel_6a_battery_level':'sensor.pixel_6a_battery_state'};
const lines=eids.map(eid=>{
  const e=rec[eid];
  const nowPct=S(eid);
  const nowChg=S(STATE[eid])==='charging';
  let line='\u2022 '+e.who+' phone';
  if(e.lowAt) line+=' dropped to '+e.lowPct+'% at '+e.lowAt;
  if(e.recovered) line+=(e.lowAt?', recovered to ':' charged to ')+e.recPct+'% at '+e.recAt;
  line+=' (now '+(nowPct!==undefined?nowPct+'%':'?')+(nowChg?', charging':', not charging')+')';
  return line;
});
flow.set('battNight',{});
node.warn('[low-batt] morning summary: '+eids.length+' phone(s)');
const ALERTS=['notify.mobile_app_np3','notify.mobile_app_pixel_6a'];
const msgTxt='Overnight while notifications were quiet:\n'+lines.join('\n');
return [ALERTS.map(a=>({payload:{action:a,data:{title:'\ud83d\udd0b Overnight battery summary',message:msgTxt,data:{notification_icon:'mdi:battery-clock'}}}}))];

const ev = msg.payload || {};
const mode    = ev.new_state ? ev.new_state.state : '';
const oldMode = (ev.old_state  && ev.old_state.state)  || '';
const guestMode = flow.get('guest_mode') || 'off';
node.warn('[house-alarm] house_mode: ' + oldMode + ' → ' + mode + (guestMode === 'on' ? ' [guest mode]' : ''));
if (mode) flow.set('mode', mode);
if (mode === 'Away') {
    // Guest mode blocks Away arming ONLY (guests moving around would trip it)
    if (guestMode === 'on') { node.warn('[house-alarm] arm away skipped — guest mode active'); return null; }
    if (flow.get('alarm_house') === 'armed_away') { node.warn('[house-alarm] arm away skipped — already armed_away'); return null; }
    return [{}, null, null, {payload:{message:'Nobody is home. Arming the house alarm.'}}];
}
if (mode === 'Sleeping') {
    // Night arming is NOT blocked by guest mode (changed 02-07-2026) — perimeter still armed overnight with guests in
    if (flow.get('alarm_house') === 'armed_night') { node.warn('[house-alarm] arm night skipped — already armed_night'); return null; }
    return [null, {}, null, null];
}
if (mode === 'Home') {
    if (oldMode === 'Away') { flow.set('awaitWelcome', {since: Date.now()}); node.warn('[house-alarm] welcome armed — awaiting front door open'); }
    const needDisarm = flow.get('alarm_house') !== 'disarmed';
    if (!needDisarm) node.warn('[house-alarm] disarm skipped — already disarmed');
    return [null, null, needDisarm ? {} : null, null];
}
return null;

const ents = Array.isArray(msg.payload) ? msg.payload : [];
const hm = ents.find(x => x.entity_id === 'input_select.house_mode');
const gm = ents.find(x => x.entity_id === 'input_boolean.guest_mode');
const mode = hm ? hm.state : '';
const guestMode = gm ? gm.state : 'off';
flow.set('guest_mode', guestMode);
const _ah=ents.find(x=>x.entity_id==='alarm_control_panel.house'); if(_ah){flow.set('alarm_house',_ah.state);global.set('alarm_house',_ah.state);}
const _as=ents.find(x=>x.entity_id==='alarm_control_panel.shed'); if(_as) global.set('alarm_shed',_as.state);
node.warn('[house-alarm] startup: house_mode=' + mode + ' guest_mode=' + guestMode);
if (!mode) return null;
flow.set('mode', mode);
msg.payload = { new_state: { state: mode }, old_state: { state: '' } };
return msg;

const ev = msg.payload || {};
const state = ev.new_state ? ev.new_state.state : '';
flow.set('guest_mode', state);
node.warn('[house-alarm] guest_mode: ' + state);
if (state === 'off') {
    // Guest left — re-evaluate current house_mode
    const mode = flow.get('mode') || '';
    node.warn('[house-alarm] guest_mode off, re-evaluating mode=' + mode);
    msg.payload = { new_state: { state: mode }, old_state: { state: '' } };
    return msg;
}
return null;

// === House Alarm reconcile (safety net for missed house_mode events) ===
// Runs periodically. Compares the CURRENT house_mode to the last one the flow PROCESSED
// (flow.mode). Only if they differ (a change was missed — e.g. Node-RED's HA connection
// blipped at the moment house_mode changed) does it re-apply, by feeding aa-hm-fn a
// synthetic event. Because it keys off flow.mode (not the alarm state), a MANUAL disarm
// — which doesn't change house_mode — is left untouched until house_mode next changes.
const ents = Array.isArray(msg.payload) ? msg.payload : [];
const S = id => { const e = ents.find(x => x.entity_id === id); return e ? e.state : undefined; };

const mode = S('input_select.house_mode');
const guestMode = S('input_boolean.guest_mode') || 'off';
if (!ents.length || !mode) return null;          // no data (e.g. get returned empty) -> do nothing

flow.set('guest_mode', guestMode);               // keep guest state fresh (its watcher could also miss an event)

const lastMode = flow.get('mode') || '';
if (mode === lastMode) return null;              // no missed change -> respect current (incl. manual) state

node.warn('[house-alarm] RECONCILE: missed house_mode change ' + lastMode + ' -> ' + mode + ' — re-applying');
flow.set('mode', mode);
msg.payload = { new_state: { state: mode }, old_state: { state: lastMode } };
return msg;                                       // -> aa-hm-fn (arms/disarms exactly like a real change)

// Night-arm retry (one shot).
// Alarmo refuses arm_night when a door/window is open: the panel STAYS 'disarmed'
// and names the culprits in attribute open_sensors. aa-hm-fn is a state-change
// one-shot on house_mode, so nothing ever tried again -- the house sat unarmed
// all night. This retries ONCE, RETRY_MIN after every blocker is closed again
// (someone got up to shut it; give them time to settle back down).
const RETRY_MIN = 20;
const RETRY_MS  = RETRY_MIN * 60 * 1000;

const ents = Array.isArray(msg.entities) ? msg.entities : [];
if (!ents.length) return null;                       // no snapshot -> can't judge
const S = id => { const e = ents.find(x => x.entity_id === id); return e && e.state; };
const FN = id => { const e = ents.find(x => x.entity_id === id);
                   return (e && e.attributes && e.attributes.friendly_name) || id; };

const hm    = S('input_select.house_mode');
const alarm = S('alarm_control_panel.house');
const now   = Date.now();

// Left Sleeping, or armed by any route -> the whole thing is off. This is also
// where the next night's state gets cleared (incl. na-fn's spoken-once flag).
if (hm !== 'Sleeping' || (alarm && alarm !== 'disarmed')) {
  if (context.get('blockers') || context.get('retryUsed') || flow.get('failSpoken')) {
    node.warn('[night-retry] stand down (house_mode=' + hm + ', alarm=' + alarm + ')');
  }
  context.set('blockers', null);
  context.set('closedSince', null);
  context.set('retryUsed', false);
  flow.set('failSpoken', false);
  return null;
}

// Capture a failed night arm: disarmed + Alarmo naming open sensors, while Sleeping.
const ev = msg.payload || {};
const ns = ev.new_state || {};
if (ev.entity_id === 'alarm_control_panel.house' && ns.state === 'disarmed' &&
    ns.attributes && ns.attributes.open_sensors) {
  if (context.get('retryUsed')) {
    node.warn('[night-retry] arm failed again -- retry already used, standing down');
  } else {
    const b = Object.keys(ns.attributes.open_sensors);
    context.set('blockers', b);
    context.set('closedSince', null);
    node.warn('[night-retry] armed blocked by: ' + b.map(FN).join(', ') + ' -- waiting for all closed');
  }
  return null;
}

const blockers = context.get('blockers');
if (!blockers || !blockers.length) return null;
if (context.get('retryUsed')) return null;

const stillOpen = blockers.filter(id => S(id) !== 'off');
if (stillOpen.length) {                              // re-opened (or never closed) -> clock resets
  if (context.get('closedSince')) node.warn('[night-retry] re-opened: ' + stillOpen.map(FN).join(', ') + ' -- timer reset');
  context.set('closedSince', null);
  return null;
}

let since = context.get('closedSince');
if (!since) {
  context.set('closedSince', now);
  node.warn('[night-retry] all closed -- arming in ' + RETRY_MIN + ' min');
  return null;
}

if (now - since < RETRY_MS) return null;             // still settling

context.set('retryUsed', true);                      // ONE retry, then stop
context.set('closedSince', null);
node.warn('[night-retry] retrying arm_night now');
return {};

const aw = flow.get('awaitWelcome');
const WINDOW = 8 * 60 * 1000;
const opened = msg.payload && msg.payload.new_state && msg.payload.new_state.state === 'on';
if (!opened) return null;
if (!aw || (Date.now() - aw.since) > WINDOW) return null;
flow.set('awaitWelcome', null);
const ents = Array.isArray(msg.entities) ? msg.entities : [];
const S = id => { const e = ents.find(x => x.entity_id === id); return e && e.state; };
const PEOPLE = flow.get('people') || [];
const home = PEOPLE.filter(p => p.name && (S(p.person) === 'home' || S(p.ping) === 'on')).map(p => p.name);
let who = null;
if (home.length === 1) who = home[0];
else if (home.length > 1) who = home.slice(0, -1).join(', ') + ' and ' + home[home.length - 1];
const message = who ? ('Welcome home, ' + who + '. The house has been disarmed.') : 'Welcome home. The house has been disarmed.';
node.warn('[house-alarm] ' + message);
return { payload: { message } };

// NFC + shed override. server-events now emits the FULL event envelope -> data under .event.
const HOUSE_TAG='f195ee10-14a9-4b65-bd10-c53c9866bcdf';
const SHED_TAG='b9ac1256-89ad-4514-b7d4-3e65ebd1c948';
const HARD=2*60*60*1000;   // 2 hour hard cap
const CLOSED=15*60*1000;   // door closed 15 min
const DOOR='binary_sensor.shed_door_contact';   // on=open, off=closed
const PEOPLE=global.get('people')||[{notify:'notify.mobile_app_np3'},{notify:'notify.mobile_app_pixel_6a'}];
const ENV=msg.payload||{};
const D=ENV.event||ENV;          // tag/state data lives under .event (envelope); flat fallback
const ET=ENV.event_type;
// outputs: 0 disarm-house | 1 disarm-shed | 2 arm-shed | 3 tts | 4 notify | 5 status-by
// WHO scanned: tag_scanned events carry the scanning phone's user in the envelope
// context (verified against the recorder 19-07-2026). Written to
// input_text.alarm_status_by ONLY on tag-initiated disarms (ha-config #39) so the
// activity card can badge them; auto re-arms stay unwritten (they ARE Node-RED).
const BY_USERS={
  'da11950c94184bf281a21b4b1a06cdb7':'Colm',
  'bfe92889b07b4798901d5d48a789262f':'Olivia',
  '5aa07e1f90c44da2aab995628305cb52':'Cian',
  '848fa8f992bb47d6a23f498d73717814':'Daire'
};
const _uid=ENV.context&&ENV.context.user_id;
const _by=(_uid&&BY_USERS[_uid])||'hand';   // unknown scanner -> neutral hand
function clrHard(){const t=context.get('hardT');if(t){clearTimeout(t);context.set('hardT',null);}}
function clrClosed(){const t=context.get('closedT');if(t){clearTimeout(t);context.set('closedT',null);}}
function tts(m){return {payload:{message:m}};}
function notif(title,message){return PEOPLE.filter(x=>x.notify).map(x=>({payload:{action:x.notify,data:{title:title,message:message,data:{notification_icon:'mdi:shield-home'}}}}));}
function rearm(why){context.set('shedOverride',false);context.set('doorOpened',false);context.set('doorOpen',false);clrHard();clrClosed();node.warn('[nfc] shed re-arm ('+why+')');node.send([null,null,{},null,null]);}
function startClosed(){clrClosed();const t=setTimeout(function(){context.set('closedT',null);rearm('door closed 15m');},CLOSED);context.set('closedT',t);node.warn('[nfc] shed door closed -> 15m re-arm timer');}
function shedOpenAlert(){
  context.set('doorOpened',true);
  node.warn('[nfc] 2h cap reached, shed door STILL OPEN -> hold disarmed + alert');
  node.send([null,null,null,
    tts('The shed door has been left open. The shed alarm is not armed and will not arm until the door is closed for fifteen minutes.'),
    notif('Shed door left open','The shed has been open for 2 hours and is still open. The shed alarm is NOT armed - it will arm 15 minutes after the door is closed.')]);
}
function hardCap(){
  context.set('hardT',null);
  if(context.get('doorOpen')){ shedOpenAlert(); }
  else { rearm('2h cap'); }
}
// TAG scans
if(ET==='tag_scanned' || D.tag_id){
  const tag=D.tag_id;
  if(tag===HOUSE_TAG){ if(global.get('alarm_house')==='disarmed'){ node.warn('[nfc] front door tag — house already disarmed, skip'); return null; } node.warn('[nfc] front door -> disarm house (by '+_by+')'); return [{},null,null,null,null,{statusBy:_by}]; }
  if(tag===SHED_TAG){
    context.set('shedOverride',true); context.set('doorOpened',false); context.set('doorOpen',false);
    clrHard(); const ht=setTimeout(hardCap, HARD); context.set('hardT',ht);
    clrClosed();
    if(global.get('alarm_shed')==='disarmed'){ node.warn('[nfc] back door tag — shed already disarmed, override started, skip disarm call'); return null; }
    node.warn('[nfc] back door -> disarm shed (2h cap, by '+_by+')');
    return [null,{},null,null,null,{statusBy:_by}];   // disarm shed + record who
  }
  return null;
}
// SHED DOOR state changes (only during override window)
if(D.entity_id===DOOR && context.get('shedOverride')){
  const ds=(D.new_state&&D.new_state.state)||null;
  const open=(ds==='on');
  context.set('doorOpen',open);
  if(open){ context.set('doorOpened',true); clrClosed(); node.warn('[nfc] shed door opened'); }
  else if(ds==='off' && context.get('doorOpened')){ startClosed(); }
  return null;
}
return null;

// 22:00 nightly: arm the shed ONLY if it is disarmed AND the door is closed.
const ents=Array.isArray(msg.payload)?msg.payload:[];
const S=id=>{const e=ents.find(x=>x.entity_id===id);return e&&e.state;};
const shed=S('alarm_control_panel.shed');
const door=S('binary_sensor.shed_door_contact');   // on=open, off=closed
if(shed==='disarmed' && door==='off'){
  node.warn('[nfc] 22:00 nightly: shed disarmed + door closed -> arm');
  return {};   // -> arm shed
}
return null;   // already armed, or door open -> do nothing

