var ent=msg.topic, state=msg.payload;
if(ent==='sensor.truenas_rsync_failed_paths'){flow.set('rsync_paths',state);return null;}
var rule=RULES[ent];
if(!rule)return null;
var fired=context.get('fired')||{};
var timers=context.get('timers')||{};
function test(){
  if(rule.op==='eq')return state===rule.val;
  if(rule.op==='in')return rule.val.indexOf(state)>=0;
  var n=parseFloat(state); if(isNaN(n))return false;
  if(rule.op==='gt')return n>rule.val;
  if(rule.op==='lt')return n<rule.val;
  return false;
}
var active=test();
var fname=(msg.ent&&msg.ent.attributes&&msg.ent.attributes.friendly_name)||ent.replace('sensor.truenas_disks_','');
function emit(nm){node.send({cat:rule.cat,sub:rule.sub,message:rule.m(state,nm),tag:rule.sub+'_'+ent});}
if(rule.for){
  if(active){
    if(fired[ent])return null;
    if(timers[ent])return null;
    var capName=fname;
    timers[ent]=setTimeout(function(){
      var tm=context.get('timers')||{};delete tm[ent];context.set('timers',tm);
      var fr=context.get('fired')||{};fr[ent]=true;context.set('fired',fr);
      emit(capName);
    },rule.for);
    context.set('timers',timers);
  }else{
    if(timers[ent]){clearTimeout(timers[ent]);delete timers[ent];context.set('timers',timers);}
    if(fired[ent]){fired[ent]=false;context.set('fired',fired);}
  }
}else{
  if(active){
    if(fired[ent])return null;
    fired[ent]=true;context.set('fired',fired);
    emit(fname);
  }else{
    if(fired[ent]){fired[ent]=false;context.set('fired',fired);}
  }
}
return null;

function dub(){return new Date().toLocaleString('en-IE',{timeZone:'Europe/Dublin',hour12:false});}
function dhour(){return parseInt(new Date().toLocaleString('en-IE',{timeZone:'Europe/Dublin',hour:'2-digit',hour12:false}),10);}
function quiet(){var h=dhour();return (h>=22||h<7);}
function hhmm(ts){return new Date(ts).toLocaleTimeString('en-IE',{timeZone:'Europe/Dublin',hour:'2-digit',minute:'2-digit'});}

if(msg.topic==='flush'){
  var held=context.get('held')||[];
  context.set('held',[]);
  if(!held.length)return null;
  var nots=[],logs=[];
  held.forEach(function(e){
    nots.push({title:e.title+' (triggered '+hhmm(e.firedAt)+')',message:e.message,ndata:e.ndata});
    logs.push({payload:dub()+'  [flush] '+e.title+' — '+e.message+'\n'});
  });
  node.send([nots,logs]);
  return null;
}

var cat=msg.cat, sub=msg.sub, message=msg.message;
