const tok = env.get("PVE_API_TOKEN"); // full PVEAPIToken=... string, from gitignored .env
const base = "https://10.0.0.251:8006/api2/json/nodes/";
const q = "/tasks?typefilter=vzdump&limit=8&source=archive";
const mk = (n) => ({ url: base + n + q, headers: { Authorization: tok }, node: n, topic: "pve" });
node.send([[ mk("proxmox"), mk("proxmox2") ]]);
