const now = Date.now()/1000;
const WINDOW = 26*3600;
const labels = {proxmox:'node1 (proxmox)', proxmox2:'node2 (proxmox2)'};
const fmt = (e) => new Date(e*1000).toLocaleString('en-IE',{timeZone:'Europe/Dublin',weekday:'short',hour:'2-digit',minute:'2-digit'});
let problems = [];
for (const r of msg.payload) {
  const lbl = labels[r.node] || r.node;
  const done = (r.tasks||[]).filter(t => t.endtime);
  const recent = done.filter(t => (now - t.endtime) < WINDOW);
  if (recent.length === 0) { problems.push('\u2022 ' + lbl + ': no backup completed in last 26h'); continue; }
  const failed = recent.filter(t => t.status !== 'OK');
  for (const f of failed) problems.push('\u2022 ' + lbl + ': backup ended \u201c' + f.status + '\u201d at ' + fmt(f.endtime));
}
const stamp = new Date().toLocaleTimeString('en-IE',{timeZone:'Europe/Dublin',hour:'2-digit',minute:'2-digit'});
if (problems.length === 0) { node.status({fill:'green',shape:'dot',text:'all OK '+stamp}); return null; }
node.status({fill:'red',shape:'dot',text:problems.length+' issue(s) '+stamp});
msg.cat = 'Backup';
msg.sub = 'Proxmox';
msg.message = problems.join('\n');
msg.tag = 'proxmox_backup';
return msg;

